import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    # Get absolute path of the directory
    abs_dir = os.path.abspath(dir_path)
    # Construct the full path and resolve it to an absolute path
    file_path = os.path.join(abs_dir, filename)
    abs_file_path = os.path.abspath(file_path)
    # Ensure the resolved path is inside the intended directory
    if not abs_file_path.startswith(abs_dir + os.sep):
        return ""
    try:
        with open(abs_file_path, 'r', encoding='utf-8') as f:
            return f.read()
    except Exception:
        return ""

