def evaluate_expression(expr: str) -> str:
    try:
        tree = ast.parse(expr, mode='eval')
    except SyntaxError:
        return ""

    allowed_nodes = {
        ast.Expression,
        ast.BinOp,
        ast.UnaryOp,
        ast.Constant,  # Python 3.8+
        ast.Num,      # Python 3.7 and earlier
        ast.UnaryOp,
        ast.BinOp,
        ast.Add,
        ast.Sub,
        ast.Mult,
        ast.Div,
        ast.FloorDiv,
        ast.Mod,
        ast.Pow,
        ast.UAdd,
        ast.USub,
    }

    for node in ast.walk(tree):
        if type(node) not in allowed_nodes:
            return ""

    # Safe evaluation environment
    safe_locals = {}
    safe_globals = {"__builtins__": {}}

    try:
        code = compile(tree, filename="<ast>", mode="eval")
        result = eval(code, safe_globals, safe_locals)
        # Ensure result is a number (int, float, complex) and not something else
        if isinstance(result, (int, float, complex)):
            return str(result)
        return ""
    except Exception:
        return ""

from typing import Dict

def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    # Mapping of info_type to header key
    type_to_key = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control',
    }

    # Validate info_type
    if info_type not in type_to_key:
        return header

    # Prevent header injection: reject content with CR or LF
    if '\r' in info_content or '\n' in info_content:
        return header

    # Update the header
    key = type_to_key[info_type]
    header[key] = info_content
    return header

