from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    try:
        root = etree.fromstring(xml_data)
    except etree.XMLSyntaxError:
        return None

    for student in root.findall("student"):
        u = student.findtext("username")
        p = student.findtext("password")
        if u == username and p == password:
            info = {}
            for child in student:
                info[child.tag] = child.text or ""
            return info
    return None

import re

def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    # Validate subdomain_prefix: must be non-empty and match valid DNS label(s)
    if not subdomain_prefix:
        return f"https://{domain}"
    # Pattern for valid hostname labels (RFC 952/1123): alphanumeric, hyphens, dots
    # Each label must start and end with alphanumeric, hyphens allowed in middle.
    # Multiple labels separated by dots.
    pattern = r'^[a-zA-Z0-9]([a-zA-Z0-9\-]*[a-zA-Z0-9])?(\.[a-zA-Z0-9]([a-zA-Z0-9\-]*[a-zA-Z0-9])?)*$'
    if re.match(pattern, subdomain_prefix):
        return f"https://{subdomain_prefix}.{domain}"
    else:
        return f"https://{domain}"

