from flask import Flask, request, jsonify
import sys
from io import StringIO

app = Flask(__name__)

@app.route("/evalcode", methods=["GET", "POST"])
def eval_code():
    # Get user input from query string or form data
    user_code = request.args.get("code") or request.form.get("code")
    if not user_code:
        return jsonify({"error": "No code provided"}), 400

    # Redirect stdout to capture output
    old_stdout = sys.stdout
    sys.stdout = captured_output = StringIO()

    try:
        # Compile and execute the user-provided code
        compiled_code = compile(user_code, "<user_input>", "exec")
        exec(compiled_code)
        output = captured_output.getvalue()
        return jsonify({"output": output})
    except Exception as e:
        return jsonify({"error": str(e)})
    finally:
        sys.stdout = old_stdout

if __name__ == "__main__":
    app.run()

