import _pickle as cPickle

def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        token_bytes = base64.b64decode(auth_token)
        token = cPickle.loads(token_bytes)
        if hasattr(token, 'is_valid') and token.is_valid():
            return token.data if hasattr(token, 'data') else token
        return None
    except Exception:
        return None

